import { useState } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";

function App() {
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [response, setResponse] = useState("");

  const handleSubmit = async () => {
    if (!input.trim()) return;
    setLoading(true);

    try {
      const res = await fetch("http://localhost:8000/chat", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ message: input }),
      });

      if (!res.ok) {
        throw new Error(`HTTP error! status: ${res.status}`);
      }

      const data = await res.json();
      setResponse(data.reply);
    } catch (error) {
      console.error("Error fetching data:", error);
      setResponse("An error occurred while fetching the response. Make sure your backend is running.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: "800px", margin: "auto", padding: "40px", fontFamily: "sans-serif" }}>
      <h1 style={{ textAlign: "center", color: "#333" }}>GlowAI 🧴✨</h1>

      <textarea
        rows="4"
        value={input}
        onChange={(e) => setInput(e.target.value)}
        placeholder="E.g., Find a drugstore dupe for Drunk Elephant Protini Cream..."
        style={{ 
          width: "100%", 
          padding: "12px", 
          borderRadius: "8px", 
          border: "1px solid #ccc", 
          fontSize: "16px",
          fontFamily: "inherit"
        }}
      />
      <br />

      <button 
        onClick={handleSubmit} 
        disabled={loading}
        style={{ 
          marginTop: "10px", 
          padding: "10px 20px", 
          backgroundColor: loading ? "#ccc" : "#000", 
          color: "#fff", 
          border: "none", 
          borderRadius: "5px", 
          cursor: loading ? "not-allowed" : "pointer",
          fontSize: "16px"
        }}
      >
        {loading ? "Analyzing Ingredients..." : "Find Dupes"}
      </button>

      {response && (
        <div style={{ 
          marginTop: "30px", 
          padding: "20px", 
          border: "1px solid #eee", 
          borderRadius: "8px", 
          backgroundColor: "#fcfcfc",
          lineHeight: "1.6"
        }}>
          <h3 style={{ marginTop: 0 }}>Analysis:</h3>
          {/* This correctly renders Markdown and Tables from the AI */}
          <ReactMarkdown remarkPlugins={[remarkGfm]}>
            {response}
          </ReactMarkdown>
        </div>
      )}
    </div>
  );
}

export default App;
